def simulate_boot() -> None:
    import time

    from rich.console import Console
    console = Console()
    steps = [
        ("[bold red]REVERSING[/] target binary...",       0.12),
        ("[bold red]PARSING[/] PE/ELF headers...",        0.10),
        ("[bold red]LOADING[/] disassembly engine...",    0.12),
        ("[bold red]ANALYZING[/] import address table...", 0.10),
        ("[bold red]INITIALIZING[/] debugger hooks...",   0.12),
        ("[bold bright_red]REVERSEQUEST[/] ONLINE!",      0.08),
    ]
    for msg, delay in steps:
        console.print(f"  [bright_black]>[/] {msg}")
        time.sleep(delay)
    console.print()


